#include <stdio.h>
#include <stdlib.h>

int canDivide(int *a, int n, int k, int minSweet) {
    int cnt = 0, cur = 0;
    for (int i = 0; i < n; ++i) {
        cur += a[i];
        if (cur >= minSweet) {
            ++cnt;
            cur = 0;
        }
    }
    return cnt >= k + 1;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K; scanf("%d %d", &N, &K);
        int *a = (int*)malloc(N * sizeof(int));
        long long total = 0;
        for (int i = 0; i < N; ++i) { scanf("%d", &a[i]); total += a[i]; }
        int lo = 1, hi = (int)total, ans = 0;
        while (lo <= hi) {
            int mid = lo + (hi - lo) / 2;
            if (canDivide(a, N, K, mid)) { ans = mid; lo = mid + 1; }
            else hi = mid - 1;
        }
        printf("%d\n", ans);
        free(a);
    }
    return 0;
}

