import java.io.*;
import java.util.*;

public class Main {
    private static boolean canDivide(int[] a, int k, int minSweet) {
        int cnt = 0, cur = 0;
        for (int v : a) {
            cur += v;
            if (cur >= minSweet) { cnt++; cur = 0; }
        }
        return cnt >= k + 1;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int K = Integer.parseInt(st.nextToken());
            int[] a = new int[N];
            st = new StringTokenizer(br.readLine());
            long total = 0;
            for (int i = 0; i < N; ++i) {
                a[i] = Integer.parseInt(st.nextToken());
                total += a[i];
            }
            int lo = 1, hi = (int) total, ans = 0;
            while (lo <= hi) {
                int mid = lo + (hi - lo) / 2;
                if (canDivide(a, K, mid)) { ans = mid; lo = mid + 1; }
                else hi = mid - 1;
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
import sys

def can_divide(arr, k, min_sweet):
    cnt = cur = 0
    for v in arr:
        cur += v
        if cur >= min_sweet:
            cnt += 1
            cur = 0
    return cnt >= k + 1

def solve():
    data = list(map(int, sys.stdin.read().split()))
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it); K = next(it)
        arr = [next(it) for _ in range(N)]
        total = sum(arr)
        lo, hi, ans = 1, total, 0
        while lo <= hi:
            mid = (lo + hi) // 2
            if can_divide(arr, K, mid):
                ans = mid
                lo = mid + 1
            else:
                hi = mid - 1
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

